import { GoogleGenAI } from "@google/genai";
import { USER_PROFILE, PROJECTS } from "../constants";

// Initialize the API client
// Note: In a real production app, you should proxy requests through a backend 
// to avoid exposing your API KEY if it's not restricted by origin.
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION = `
Você é um assistente virtual inteligente integrado ao portfólio de ${USER_PROFILE.name}.
Seu objetivo é responder perguntas de recrutadores e visitantes sobre o ${USER_PROFILE.name}, suas habilidades e projetos.

Aqui estão os dados sobre o ${USER_PROFILE.name}:
Bio: ${USER_PROFILE.bio}
Cargo: ${USER_PROFILE.role}
Habilidades: ${USER_PROFILE.skills.join(", ")}

Aqui estão os projetos dele:
${PROJECTS.map(p => `- ${p.title}: ${p.description} (Techs: ${p.tags.join(', ')})`).join('\n')}

Diretrizes:
- Seja profissional, mas amigável e moderno.
- Responda em Português do Brasil.
- Seja conciso.
- Se perguntarem sobre contato, sugira olhar os links no rodapé.
`;

export const streamChatResponse = async function* (
  message: string, 
  history: { role: 'user' | 'model', text: string }[]
) {
  try {
    const chat = ai.chats.create({
      model: 'gemini-3-flash-preview',
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const result = await chat.sendMessageStream({ message });

    for await (const chunk of result) {
      if (chunk.text) {
        yield chunk.text;
      }
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    yield "Desculpe, estou tendo dificuldades para processar sua pergunta no momento. Verifique a chave de API.";
  }
};

