        // Dispara quando 10% do elemento estiver visível
        if (entry.isIntersecting) {
          setIsVisible(true);
          // Opcional: desconectar se quiser que a animação rode apenas uma vez
          observer.disconnect();
        }
      },
      { threshold: 0.1 }
